body:
# Problem report

## Brief
* I want to update yosys tool from v0.11 to v0.19
* I used to generate smt-lib model from verilog sources
* Between v0.14 and v0.15 the RTLIL generated by the verilog frontend has changed and therefore the smt-lib model is different.
* Here is an example explaining why I think there is a problem
* Do not hesitate to ask for further information if the issue is not clear enough
  
## Problem description

### Expected behavior
* cv32e40p_fifo.v is a simple fifo (or circular buffer) module with a queue size of 2 bytes used in the [CV32E40P processor](https://github.com/openhwgroup/cv32e40p)
* when a `push` is performed, `data_in` is written in `mem` at the address pointed by `write_ptr`
* when a `pop` is performed, the data at the address pointed by `read_ptr` is produced on the output `data_out`

### Actual behavior (observed on yosys v0.15 and later)
* the smt-lib model generated by yosys-v0.14 works well, while the one produced by yosys-v0.15 **cannot write data in mem.**

## To reproduce the problem

``` bash
# build the smt model
yosys -p "read_verilog cv32e40p_fifo.v;
          prep -top cv32e40p_fifo;
          async2sync; dffunmap;
          write_smt2 -wires cv32e40p_fifo.smt2"
```

``` bash
# run smtbmc to write in the fifo
yosys-smtbmc -s yices --presat --dump-vcd cex.vcd --smtc constr.smtc --smtc property.smtc cv32e40p_fifo.smt2
```

### Comments and observations

* We start the bmc with a reset from step 0 to step 3 (`constr.smtc`). The content of the fifo (i.e., signal `mem_n`) is therefore {0x0, 0x0} (this is a 2-byte queue).
* The property given to the solver (`property.smtc`) ensures that the content of the fifo cannot be 0xbabecafe0123deca i.e., we cannot write this data into the fifo. Naturally this property will fail as the proper operation of the fifo permits to write such a data in the queue. The smt solver produces the corresponding trace `cex.vcd`.
* However this property will be verified with yosys-v0.15 highlighting that **we cannot write data** in the fifo (more precisely we cannot write in the MSB of the fifo).


## Material

### constr.smtc
``` 
state 0:3
assume (= [rst_ni] false)
state 4:*
assume (= [rst_ni] true)
```

### property.smtc
```
always
assert (distinct [mem_n] #xbabecafe0123deca)
```

### cv32e40p_fifo.v
``` verilog
module cv32e40p_fifo (
	clk_i,
	rst_ni,
	flush_i,
	flush_but_first_i,
	testmode_i,
	full_o,
	empty_o,
	cnt_o,
	data_i,
	push_i,
	data_o,
	pop_i
);
	parameter [0:0] FALL_THROUGH = 1'b0;
	parameter [31:0] DATA_WIDTH = 32;
	parameter [31:0] DEPTH = 2;
	parameter [31:0] ADDR_DEPTH = (DEPTH > 1 ? $clog2(DEPTH) : 1);
	input wire clk_i;
	input wire rst_ni;
	input wire flush_i;
	input wire flush_but_first_i;
	input wire testmode_i;
	output wire full_o;
	output wire empty_o;
	output wire [ADDR_DEPTH:0] cnt_o;
	input wire [DATA_WIDTH - 1:0] data_i;
	input wire push_i;
	output reg [DATA_WIDTH - 1:0] data_o;
	input wire pop_i;
	localparam [31:0] FIFO_DEPTH = (DEPTH > 0 ? DEPTH : 1);
	reg gate_clock;
	reg [ADDR_DEPTH - 1:0] read_pointer_n;
	reg [ADDR_DEPTH - 1:0] read_pointer_q;
	reg [ADDR_DEPTH - 1:0] write_pointer_n;
	reg [ADDR_DEPTH - 1:0] write_pointer_q;
	reg [ADDR_DEPTH:0] status_cnt_n;
	reg [ADDR_DEPTH:0] status_cnt_q;
	reg [(FIFO_DEPTH * DATA_WIDTH) - 1:0] mem_n;
	reg [(FIFO_DEPTH * DATA_WIDTH) - 1:0] mem_q;
	assign cnt_o = status_cnt_q;
	generate
		if (DEPTH == 0) begin : gen_zero_depth
			assign empty_o = ~push_i;
			assign full_o = ~pop_i;
		end
		else begin : gen_non_zero_depth
			assign full_o = status_cnt_q == FIFO_DEPTH[ADDR_DEPTH:0];
			assign empty_o = (status_cnt_q == 0) & ~(FALL_THROUGH & push_i);
		end
	endgenerate
	always @(*) begin : read_write_comb
		read_pointer_n = read_pointer_q;
		write_pointer_n = write_pointer_q;
		status_cnt_n = status_cnt_q;
		data_o = (DEPTH == 0 ? data_i : mem_q[read_pointer_q * DATA_WIDTH+:DATA_WIDTH]);
		mem_n = mem_q;
		gate_clock = 1'b1;
		if (push_i && ~full_o) begin
			mem_n[write_pointer_q * DATA_WIDTH+:DATA_WIDTH] = data_i;
			gate_clock = 1'b0;
			if (write_pointer_q == (FIFO_DEPTH[ADDR_DEPTH - 1:0] - 1))
				write_pointer_n = 1'sb0;
			else
				write_pointer_n = write_pointer_q + 1;
			status_cnt_n = status_cnt_q + 1;
		end
		if (pop_i && ~empty_o) begin
			if (read_pointer_n == (FIFO_DEPTH[ADDR_DEPTH - 1:0] - 1))
				read_pointer_n = 1'sb0;
			else
				read_pointer_n = read_pointer_q + 1;
			status_cnt_n = status_cnt_q - 1;
		end
		if (((push_i && pop_i) && ~full_o) && ~empty_o)
			status_cnt_n = status_cnt_q;
		if ((FALL_THROUGH && (status_cnt_q == 0)) && push_i) begin
			data_o = data_i;
			if (pop_i) begin
				status_cnt_n = status_cnt_q;
				read_pointer_n = read_pointer_q;
				write_pointer_n = write_pointer_q;
			end
		end
	end
	always @(posedge clk_i or negedge rst_ni)
		if (~rst_ni) begin
			read_pointer_q <= 1'sb0;
			write_pointer_q <= 1'sb0;
			status_cnt_q <= 1'sb0;
		end
		else
			case (1'b1)
				flush_i: begin
					read_pointer_q <= 1'sb0;
					write_pointer_q <= 1'sb0;
					status_cnt_q <= 1'sb0;
				end
				flush_but_first_i: begin
					read_pointer_q <= (status_cnt_q > 0 ? read_pointer_q : {ADDR_DEPTH {1'sb0}});
					write_pointer_q <= (status_cnt_q > 0 ? read_pointer_q + 1 : {ADDR_DEPTH {1'sb0}});
					status_cnt_q <= (status_cnt_q > 0 ? 1'b1 : {(ADDR_DEPTH >= 0 ? ADDR_DEPTH + 1 : 1 - ADDR_DEPTH) {1'sb0}});
				end
				default: begin
					read_pointer_q <= read_pointer_n;
					write_pointer_q <= write_pointer_n;
					status_cnt_q <= status_cnt_n;
				end
			endcase
	always @(posedge clk_i or negedge rst_ni)
		if (~rst_ni)
			mem_q <= 1'sb0;
		else if (!gate_clock)
			mem_q <= mem_n;
endmodule

```
